using System;using System.Collections.Generic;class A{static int W,H,n;static string[]G;static int[,]I;static int[]S=new int[1000001];static void F(int r,int c){n++;var q=new Queue<(int,int)>();q.Enqueue((r,c));I[r,c]=n;int a=0;int[]dx={1,-1,0,0},dy={0,0,1,-1};while(q.Count>0){var(y,x)=q.Dequeue();a++;for(int i=0;i<4;i++){int ny=y+dy[i],nx=x+dx[i];if(ny>=0&&ny<H&&nx>=0&&nx<W&&I[ny,nx]<0&&G[ny][nx]=='O'){I[ny,nx]=n;q.Enqueue((ny,nx));}}}S[n]=a;}static void Main(){W=int.Parse(Console.ReadLine());H=int.Parse(Console.ReadLine());G=new string[H];I=new int[H,W];for(int i=0;i<H;i++){G[i]=Console.ReadLine();for(int j=0;j<W;j++)I[i,j]=-1;}int q=int.Parse(Console.ReadLine());while(q-->0){var p=Console.ReadLine().Split(' ');int x=int.Parse(p[0]),y=int.Parse(p[1]);if(G[y][x]!='O')Console.WriteLine(0);else{if(I[y,x]<0)F(y,x);Console.WriteLine(S[I[y,x]])}}}}